import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { ArrowUpLeft, Building2, FolderArchive, Loader2 } from "lucide-react";
import AppShell from "../components/AppShell";
import { Badge } from "../components/ui/badge";
import { Button } from "../components/ui/button";
import { api, getErrorMessage } from "../lib/api";

export default function DepartmentsPage() {
  const [departments, setDepartments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    api.get("/departments")
      .then(({ data }) => setDepartments(data))
      .catch((err) => setError(getErrorMessage(err)))
      .finally(() => setLoading(false));
  }, []);

  return (
    <AppShell title="اختيار الإدارة" subtitle="اختر الإدارة المطلوبة لبدء أرشفة الملفات والعضويات.">
      <section className="grid gap-6 lg:grid-cols-[1fr_360px]" data-testid="departments-page">
        <div className="grid gap-4 md:grid-cols-2" data-testid="departments-grid">
          {loading && <div className="flex items-center gap-2 text-slate-500" data-testid="departments-loading"><Loader2 className="h-4 w-4 animate-spin" /> تحميل الإدارات...</div>}
          {error && <div className="rounded-lg border border-red-200 bg-red-50 p-4 text-red-700" data-testid="departments-error-message">{error}</div>}
          {departments.filter((department) => department.active).map((department) => (
            <Link
              key={department.id}
              to={`/project/${department.id}`}
              className="group relative block overflow-hidden rounded-2xl bg-gradient-to-br from-blue-600 to-blue-900 p-6 shadow-lg shadow-blue-500/50 transition-all duration-500 hover:scale-[1.02] hover:shadow-2xl"
              data-testid={`department-card-${department.id}`}
            >
              {/* Glassmorphism overlay */}
              <div className="absolute inset-0 bg-white/5 backdrop-blur-[1px]" />

              {/* Content */}
              <div className="relative">
                {/* Header: Icon + Code */}
                <div className="flex items-start justify-between gap-4">
                  <div className="grid h-16 w-16 flex-shrink-0 place-items-center rounded-xl bg-white/20 backdrop-blur-sm" data-testid={`department-icon-${department.id}`}>
                    <Building2 className="h-8 w-8 text-white" />
                  </div>
                  <div className="rounded-full bg-white/90 px-4 py-2 backdrop-blur-sm" data-testid={`department-code-${department.id}`}>
                    <div className="text-center text-sm font-extrabold text-slate-900">
                      {department.code || "—"}
                    </div>
                  </div>
                </div>

                {/* Title & Description */}
                <div className="mt-6">
                  <h2 className="text-2xl font-extrabold text-white drop-shadow-md" data-testid={`department-name-${department.id}`}>
                    {department.name}
                  </h2>
                  {department.description && (
                    <p className="mt-2 text-sm leading-relaxed text-white/90" data-testid={`department-description-${department.id}`}>
                      {department.description}
                    </p>
                  )}
                </div>

                {/* CTA Button */}
                <div className="mt-6">
                  <div className="inline-flex items-center gap-2 rounded-lg bg-white px-6 py-3 text-sm font-bold text-slate-900 shadow-lg transition-all duration-300 group-hover:scale-105 group-hover:shadow-xl">
                    <span>فتح الإدارة</span>
                    <ArrowUpLeft className="h-4 w-4 transition-transform duration-300 group-hover:-translate-x-1 group-hover:-translate-y-1" />
                  </div>
                </div>
              </div>

              {/* Shine effect on hover */}
              <div className="absolute -inset-full top-0 block h-full w-1/2 -skew-x-12 transform bg-gradient-to-r from-transparent to-white opacity-20 transition-all duration-700 group-hover:left-full" />
            </Link>
          ))}
        </div>

        <aside className="rounded-lg border border-slate-200 bg-white p-6" data-testid="departments-summary-panel">
          <div className="grid h-12 w-12 place-items-center rounded-lg bg-emerald-50 text-emerald-700" data-testid="departments-summary-icon">
            <FolderArchive className="h-6 w-6" />
          </div>
          <h3 className="mt-6 text-xl font-bold text-slate-950" data-testid="departments-summary-title">التحكم من الأدمن</h3>
          <p className="mt-3 text-sm leading-6 text-slate-500" data-testid="departments-summary-text">يمكنك إضافة الإدارات وتعديل بيانات اتصال الطابعة/الماسح من صفحة الأدمن.</p>
          <Button asChild className="mt-6 w-full bg-[#0047AB] hover:bg-[#003380]" data-testid="go-to-admin-button">
            <Link to="/admin">فتح صفحة الأدمن</Link>
          </Button>
        </aside>
      </section>
    </AppShell>
  );
}
